import{_ as a,o as b,c as t,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"迅牙猎弓","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/迅牙猎弓.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/迅牙猎弓.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/迅牙猎弓.md"};function d(l,e,_,i,p,c){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"迅牙猎弓",tabindex:"-1"},[n("迅牙猎弓 "),r("a",{class:"header-anchor",href:"#迅牙猎弓","aria-label":'Permalink to "迅牙猎弓"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌030")])])],-1),s('<h1 id="迅牙猎弓-1" tabindex="-1">迅牙猎弓 <a class="header-anchor" href="#迅牙猎弓-1" aria-label="Permalink to &quot;迅牙猎弓&quot;">​</a></h1><p>【迅牙猎弓】<br> C+1250<br> “它很好用”<br> “它会咬住你”<br> “它会吃掉你”<br> 这是一把通体白色的弓，上面布满了各种尺寸的兽牙，充斥着蛮荒的气息。<br> 这是一把来自于未知的，古老的时刻的猎弓<br> 最强大的猎人赋予了它躯体<br> 最强大的猎物赋予了它灵性<br> 它将是你狩猎时最好的伙伴，也是你最好的工具<br> 它那来自于猎物的本能与狩猎的灵性是那样残缺且混沌。<br> 但它那残缺混沌的灵性中只有一个想法——让我咬住它！让我咬住下一头猎物！<br> 迅牙猎弓拥有武器伤害11l 高速3 破甲1 双手 1弹匣 40米射程 体积3<br> 而持有它时，你将获得以下能力<br> 【狩猎的嗅觉】<br> 我嗅到了，这就是你的弱点。<br> 它们如此明显，而且就像落日余晖一般橙红的果实一样——香甜，可口，怡人。<br> 在你进入战斗后的第二个回合，迅牙猎弓因狩猎而逐渐活跃的灵性将赋予你敏锐的狩猎直觉，这种直觉使得你能够嗅到猎物的弱点，此时，你对猎物造成的攻击能够将1点严重伤害转为1点韧性伤害，这种状态将会在战斗结束后清空。<br> 【狩猎之灵】<br> 在你的回合时，看选择消耗一个移动动作主动调动猎牙的灵性，这会使得猎牙赋予激发出的箭矢【猎牙】或【追狩】效果，持续一场景。<br> 效果持续期间，可在【猎牙】与【追狩】中进行效果切换<br> 切换【猎牙】或【追狩】效果则需要一个额外的迅捷动作进行。<br> 【猎牙】<br> 咬住，不要松口<br> 这就是狩猎的法则<br> 一道苍白的弧光，犹如猎兽的牙齿钉入猎物的身体中。<br> 你知道的，你一直都知道，到底攻击哪些部位会给予猎物最严重的伤势，而剩下的，就交给猎牙吧。<br> 看见了吗？猎牙咬穿它了皮肉，洞穿它了生机。<br> 至于剩下的残躯？<br> 就继续啃咬它吧，继续狩猎它吧，它的伤势不会允许它支撑太久，死亡会离它越来越近。<br> 你的攻击将附带b级的创伤来源重伤效果。<br> 【追狩】<br> 猎物会逃跑，但不必担心<br> 猎牙会留下专属的印记，那是它所标记的猎物<br> 那就让它逃吧<br> 然后就顺着猎物气味的方向，顺着那条血腥的长廊跟上它吧<br> 猎牙的齿痕不会消失太快<br> 那流出的鲜血就是猎牙进一步的追狩<br> 看着它慢慢死去吧，它已无路可走。<br> 你的攻击将附带1点不可豁免流血点数。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
